urlset:

  {{ config.url | uriencode }}
  {{ sNow | formatDate }}
  daily
  1.0


{% for page in pages %}
  {% if page.source == 'about/index.md' and page.updated %}

    {{ config.url | uriencode }}/about
    {{ page.updated | formatDate }}
    monthly
    0.6

  {% endif %}
{% endfor %}

{% for post in posts %}

  {{ post.permalink | uriencode }}
  {{ post.updated | formatDate }}
  monthly
  0.8

{% endfor %}


  {{ config.url | uriencode }}/tags
  {{ sNow | formatDate }}
  daily
  0.2


{% for tag in tags %}

  {{ tag.permalink | uriencode }}
  {{ sNow | formatDate }}
  weekly
  0.2

{% endfor %}


  {{ config.url | uriencode }}/categories
  {{ sNow | formatDate }}
  daily
  0.2


{% for cat in categories %}

  {{ cat.permalink | uriencode }}
  {{ sNow | formatDate }}
  weekly
  0.2

{% endfor %}
